/**
 * Notification log model for tracking sent notification history.
 *
 * Every notification that passes through the notification system is
 * logged here with delivery status, channel, and metadata for auditing
 * and querying.
 */

import type { NotificationChannel, NotificationType, NotificationPriority } from './notification.js';

export type DeliveryStatus = 'delivered' | 'failed';

export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  subject: string;
  channel: NotificationChannel;
  type: NotificationType;
  priority: NotificationPriority;
  status: DeliveryStatus;
  error?: string;
  metadata?: Record<string, string>;
  timestamp: Date;
}

export interface NotificationLogQuery {
  recipient?: string;
  channel?: NotificationChannel;
  type?: NotificationType;
  status?: DeliveryStatus;
  from?: Date;
  to?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      subject: record['subject'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      priority: record['priority'] as string as NotificationLog['priority'],
      status: record['status'] as DeliveryStatus,
      error: record['error'] as string | undefined,
      metadata: record['metadata'] ? JSON.parse(record['metadata'] as string) as Record<string, string> : undefined,
      timestamp: new Date(record['timestamp'] as string),
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      subject: entity.subject,
      channel: entity.channel,
      type: entity.type,
      priority: entity.priority,
      status: entity.status,
      error: entity.error,
      metadata: entity.metadata ? JSON.stringify(entity.metadata) : undefined,
      timestamp: entity.timestamp.toISOString(),
    };
  }

  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  findByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.findAll((log) => log.status === status);
  }

  findByDateRange(from: Date, to: Date): NotificationLog[] {
    return this.findAll((log) => log.timestamp >= from && log.timestamp <= to);
  }
}

/**
 * Notification history service — tracks all sent notifications for auditing.
 *
 * Integrates with the notification system via EventBus, listening to
 * notification:sent and notification:failed events. Every notification
 * that flows through the system is logged with delivery status.
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationSentEvent, NotificationFailedEvent } from '../events/event-types.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type { NotificationLog, NotificationLogQuery } from '../models/notification-log.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetNotificationLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(
    private repository: NotificationLogRepository,
    private eventBus: EventBus,
  ) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
      this.logSentNotification(event);
    });

    this.eventBus.on<NotificationFailedEvent>('notification:failed', (event) => {
      this.logFailedNotification(event);
    });
  }

  private logSentNotification(event: NotificationSentEvent): void {
    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: event.notification.id,
      recipient: event.notification.recipient,
      subject: event.notification.subject,
      channel: event.channel,
      type: event.notification.type,
      priority: event.notification.priority,
      status: 'delivered',
      metadata: event.notification.metadata,
      timestamp: event.timestamp,
    };

    this.repository.save(log);
    this.logger.info(`Logged sent notification ${log.notificationId} to ${log.recipient}`);
  }

  private logFailedNotification(event: NotificationFailedEvent): void {
    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: '',
      recipient: event.recipient,
      subject: event.subject,
      channel: event.channel,
      type: 'system_alert',
      priority: 'normal',
      status: 'failed',
      error: event.error,
      timestamp: event.timestamp,
    };

    this.repository.save(log);
    this.logger.info(`Logged failed notification to ${log.recipient}: ${event.error}`);
  }

  query(filter: NotificationLogQuery): NotificationLog[] {
    return this.repository.findAll((log) => {
      if (filter.recipient && log.recipient !== filter.recipient) return false;
      if (filter.channel && log.channel !== filter.channel) return false;
      if (filter.type && log.type !== filter.type) return false;
      if (filter.status && log.status !== filter.status) return false;
      if (filter.from && log.timestamp < filter.from) return false;
      if (filter.to && log.timestamp > filter.to) return false;
      return true;
    });
  }

  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  getByType(type: NotificationLogQuery['type']!): NotificationLog[] {
    return this.repository.findByType(type!);
  }

  getByDateRange(from: Date, to: Date): NotificationLog[] {
    return this.repository.findByDateRange(from, to);
  }

  getAll(): NotificationLog[] {
    return this.repository.findAll();
  }

  getCount(): number {
    return this.repository.count();
  }
}

