import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let eventBus: EventBus;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    repository = new NotificationLogRepository(db);
    resetNotificationLogIdCounter();
    resetNotificationIdCounter();
    historyService = new NotificationHistoryService(repository, eventBus);
  });

  describe('event logging', () => {
    it('should log a sent notification from notification:sent event', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0001',
          recipient: 'alice@example.com',
          subject: 'Order Confirmation',
          body: 'Your order has been placed.',
          channel: 'email',
          type: 'order_confirmation',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date('2026-01-15T10:00:00Z'),
        },
        channel: 'email',
        timestamp: new Date('2026-01-15T10:00:00Z'),
      });

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.id).toBe('nlog-0001');
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.priority).toBe('normal');
      expect(logs[0]?.status).toBe('delivered');
    });

    it('should log a failed notification from notification:failed event', async () => {
      await eventBus.emit({
        type: 'notification:failed',
        recipient: 'bob@example.com',
        subject: 'Order Update',
        channel: 'email',
        error: 'SMTP connection refused',
        timestamp: new Date('2026-01-15T10:00:00Z'),
      });

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.recipient).toBe('bob@example.com');
      expect(logs[0]?.status).toBe('failed');
      expect(logs[0]?.error).toBe('SMTP connection refused');
    });

    it('should preserve notification metadata in logs', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0001',
          recipient: 'alice@example.com',
          subject: 'Order Confirmation',
          body: 'Your order has been placed.',
          channel: 'email',
          type: 'order_confirmation',
          priority: 'high',
          status: 'sent',
          metadata: { orderId: 'order-123' },
          sentAt: new Date(),
        },
        channel: 'email',
        timestamp: new Date(),
      });

      const logs = historyService.getAll();
      expect(logs[0]?.metadata).toEqual({ orderId: 'order-123' });
      expect(logs[0]?.priority).toBe('high');
    });

    it('should generate sequential log IDs', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0001',
          recipient: 'alice@example.com',
          subject: 'Test 1',
          body: 'Body 1',
          channel: 'email',
          type: 'order_confirmation',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date(),
        },
        channel: 'email',
        timestamp: new Date(),
      });

      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0002',
          recipient: 'bob@example.com',
          subject: 'Test 2',
          body: 'Body 2',
          channel: 'webhook',
          type: 'order_status_update',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date(),
        },
        channel: 'webhook',
        timestamp: new Date(),
      });

      const logs = historyService.getAll();
      expect(logs).toHaveLength(2);
      expect(logs[0]?.id).toBe('nlog-0001');
      expect(logs[1]?.id).toBe('nlog-0002');
    });
  });

  describe('query by recipient', () => {
    beforeEach(async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0001',
          recipient: 'alice@example.com',
          subject: 'Alice Notification',
          body: 'For Alice',
          channel: 'email',
          type: 'order_confirmation',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date(),
        },
        channel: 'email',
        timestamp: new Date(),
      });

      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0002',
          recipient: 'bob@example.com',
          subject: 'Bob Notification',
          body: 'For Bob',
          channel: 'email',
          type: 'order_status_update',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date(),
        },
        channel: 'email',
        timestamp: new Date(),
      });
    });

    it('should return logs for a specific recipient', () => {
      const aliceLogs = historyService.getByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(1);
      expect(aliceLogs[0]?.subject).toBe('Alice Notification');
    });

    it('should return empty array for unknown recipient', () => {
      expect(historyService.getByRecipient('unknown@example.com')).toHaveLength(0);
    });
  });

  describe('query by type', () => {
    beforeEach(async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0001',
          recipient: 'alice@example.com',
          subject: 'Order Confirmation',
          body: 'Confirmed',
          channel: 'email',
          type: 'order_confirmation',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date(),
        },
        channel: 'email',
        timestamp: new Date(),
      });

      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0002',
          recipient: 'alice@example.com',
          subject: 'Status Update',
          body: 'Updated',
          channel: 'email',
          type: 'order_status_update',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date(),
        },
        channel: 'email',
        timestamp: new Date(),
      });
    });

    it('should return logs filtered by notification type', () => {
      const confirmations = historyService.getByType('order_confirmation');
      expect(confirmations).toHaveLength(1);
      expect(confirmations[0]?.subject).toBe('Order Confirmation');
    });
  });

  describe('query by date range', () => {
    beforeEach(async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0001',
          recipient: 'alice@example.com',
          subject: 'January Notification',
          body: 'Jan',
          channel: 'email',
          type: 'order_confirmation',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date('2026-01-15T10:00:00Z'),
        },
        channel: 'email',
        timestamp: new Date('2026-01-15T10:00:00Z'),
      });

      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0002',
          recipient: 'alice@example.com',
          subject: 'March Notification',
          body: 'Mar',
          channel: 'email',
          type: 'order_status_update',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date('2026-03-15T10:00:00Z'),
        },
        channel: 'email',
        timestamp: new Date('2026-03-15T10:00:00Z'),
      });
    });

    it('should return logs within date range', () => {
      const janLogs = historyService.getByDateRange(
        new Date('2026-01-01T00:00:00Z'),
        new Date('2026-02-01T00:00:00Z'),
      );
      expect(janLogs).toHaveLength(1);
      expect(janLogs[0]?.subject).toBe('January Notification');
    });

    it('should return all logs when range covers everything', () => {
      const allLogs = historyService.getByDateRange(
        new Date('2025-01-01T00:00:00Z'),
        new Date('2027-01-01T00:00:00Z'),
      );
      expect(allLogs).toHaveLength(2);
    });

    it('should return empty when range matches nothing', () => {
      const noLogs = historyService.getByDateRange(
        new Date('2026-06-01T00:00:00Z'),
        new Date('2026-07-01T00:00:00Z'),
      );
      expect(noLogs).toHaveLength(0);
    });
  });

  describe('combined query', () => {
    beforeEach(async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0001',
          recipient: 'alice@example.com',
          subject: 'Alice Order',
          body: 'Order',
          channel: 'email',
          type: 'order_confirmation',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date('2026-01-15T10:00:00Z'),
        },
        channel: 'email',
        timestamp: new Date('2026-01-15T10:00:00Z'),
      });

      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0002',
          recipient: 'bob@example.com',
          subject: 'Bob Order',
          body: 'Order',
          channel: 'webhook',
          type: 'order_confirmation',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date('2026-01-15T10:00:00Z'),
        },
        channel: 'webhook',
        timestamp: new Date('2026-01-15T10:00:00Z'),
      });

      await eventBus.emit({
        type: 'notification:failed',
        recipient: 'alice@example.com',
        subject: 'Failed Alert',
        channel: 'email',
        error: 'Connection refused',
        timestamp: new Date('2026-02-15T10:00:00Z'),
      });
    });

    it('should filter by multiple criteria', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        status: 'delivered',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.subject).toBe('Alice Order');
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.error).toBe('Connection refused');
    });

    it('should return all when no filters provided', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });

    it('should combine date range with other filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        from: new Date('2026-02-01T00:00:00Z'),
        to: new Date('2026-03-01T00:00:00Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.status).toBe('failed');
    });
  });

  describe('count', () => {
    it('should return 0 when no logs exist', () => {
      expect(historyService.getCount()).toBe(0);
    });

    it('should return correct count after logging', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: {
          id: 'notif-0001',
          recipient: 'alice@example.com',
          subject: 'Test',
          body: 'Test',
          channel: 'email',
          type: 'order_confirmation',
          priority: 'normal',
          status: 'sent',
          sentAt: new Date(),
        },
        channel: 'email',
        timestamp: new Date(),
